from collections import Counter

def solve(n: int) -> int:
    def is_special(num: int) -> bool:
        s = str(num)
        if s != s[::-1]:
            return False
        count = Counter(s)
        for k, v in count.items():
            if v != int(k):
                return False
        return True

    i = n + 1
    while True:
        if is_special(i):
            return i
        i += 1
