from typing import Dict

def is_special(num: int) -> bool:
    s = str(num)
    if s != s[::-1]:
        return False
    count: Dict[int, int] = {}
    for c in s:
        k = int(c)
        count[k] += 1
    for k, v in count.items():
        if v != k:
            return False
    return True

def solve(n: int) -> int:
    i = n + 1
    while True:
        if is_special(i):
            return i
        i += 1
